import java.io.*;
import java.net.*;

public class java_47027_SocketServer_A08 {
    public static void main (String[] args) throws Exception{
        ServerSocket server = new ServerSocket(4242); // port number should be a large prime and open for connections only; here we use 10,793 as an example. If not free then select another available one in the range of your machine's ports (usually between ~65k-~85K)
        System.out.println("Server started on port " + server.getLocalPort()); // prints out what our current localport is to see if it matches with a running socket program – this will make the connection fail quickly once you start both servers and try sending from one of them, as they won't know which client/server IP:PORT pair should be matched up
        while (true) { // infinite loop so server can listen for incoming connections forever until it is manually stopped. By default a ServerSocket created will block if there are no pending connection requests and thus could not serve any clients till we close the socket otherwise, this has been omitted to keep simple – but you might want some kind of error handling in production code
            Socket client = server.accept(); // Accepts incoming connections from other sockets on port specified by ServerSocket (in its constructor). The return value is a new instance that represents the connection socket, and can be passed around as required – it'll block if there are no pending requests to accept before this thread wakes up
            System.out.println("New client connected from " + client.getRemoteSocketAddress()); // prints out what our current remote/connected IP address is for verification purposes; in a live production environment, you would want logging mechanisms and not just printouts here – but that's the same as before - we use this to debug any issues
            DataInputStream dataIn = new DataInputStream(client.getInputStream()); // gets input stream from client socket (connection) for reading user inputs; streams can be read a block at once using BufferedReader or similar, and line by lines with buffers – but in our case we'll just use the standard I/O methods
            String message = dataIn.readUTF(); // reads what is on stream as UTF string from client socket (connection) - this will be an external user input to send back; returns a simple text based response of whatever you sent it – but in our case we'll just use the standard I/O methods
            DataOutputStream dataOut = new DataOutputStream(client.getOutputStream()); // gets output stream from client socket (connection) for writing out server responses, and other sockets too; sends back a simple text response to user asking hello – but in our case we'll just use the standard I/O methods
            message += " Server received your message!";// appends string which contains information about what has been read from client socket (connection) - this is server side equivalent of echo. In a live production environment, you would want logging mechanisms and not just printouts here – but that's the same as before
            dataOut.writeUTF(message); // writes UTF string to stream; sends what we have written onto user socket (connection) - this is server side equivalent of echo back from client part in terms if you sent it out previously, then finally prints a response message – but again using standard I/O methods
            dataOut.flush();// flushes the output buffer so that all lines are send immediately as one and sends EOF signal to other end - this is server side equivalent of echo back from client part in terms if you sent it out previously, then finally prints a response message – but again using standard I/O methods
            dataIn.close();// closes the input stream on socket (connection) so no longer used when sending or receiving further messages - this is server side equivalent of end-of-transaction in case if any error happened and we need to clean up resources before exit – but again using standard I/O methods
            client.close(); // close connection with the specific user, once all data has been read from him so no longer used here after - this is server side equivalent of end transaction when not needed anymore because done sending or receiving further messages and we need to clean up resources before exit – but again using standard I/O methods
        }//end while loop   in an infinite ServerSocket based application, the client may close connection with its socket at any time. But our server will remain active by listening on this port until it is manually stopped or closed as per requirement and for debugging purposes only – but you would want to include error handling mechanisms if required
    }//end main function   when your program starts, the ServerSocket object opens a TCP/IP socket in specific mode (SERVER_MODE). This will block once there are no pending connections. Then it enters an infinite while loop until stopped manually by user using CTRL+C or similar keyboard signals – but you would want to include error handling mechanisms if required
}//end class SimpleSocketServer   this is the entry point of your Server-side program, and can be tested from command line as well. In a production environment however it should not block indefinitely unless there are no pending requests for accepting connections which must also close itself when these situations occur – but again you would want to include error handling mechanisms if required